#include <bits/stdc++.h>
using namespace std;
const int N=2050;
int n,m;
string s;
struct node
{
	int tr[N][N];
	void add(int x,int y,int z)
	{
		for(int i=x;i<=n;i+=(i&(-i)))
		{
			for(int j=y;j<=m;j+=(j&(-j)))
			{
				tr[i][j]+=z;
			}
		}
	}
	int query(int x,int y)
	{
		int sum=0;
		for(int i=x;i;i-=(i&-i))
		{
			for(int j=y;j;j-=(j&(-j)))
			{
				sum+=tr[i][j];
			}
		}
		return sum;
	}
}a,b,c,d;
int fun(int x,int y)
{
	return a.query(x,y)*(x*y+x+y+1)
			-b.query(x,y)*(y+1)
			-c.query(x,y)*(x+1)
			+d.query(x,y);
}
void fun2(int x,int y,int z)
{
	a.add(x,y,z);
	b.add(x,y,z*x);
	c.add(x,y,z*y);
	d.add(x,y,z*x*y);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>s>>n>>m;
	while(cin>>s)
	{
		int aa,b,c,d,x;
		cin>>aa>>b>>c>>d;
		if(s=="L")
		{
			cin>>x;
			fun2(aa,b,x);
			fun2(aa,d+1,-x);
			fun2(c+1,b,-x);
			fun2(c+1,d+1,x);
		}
		else
		{
//			cout<<fun(c,d)<<" - "<<fun(aa-1,d)<<" - "<<fun(c,b-1)<<" + "<<fun(aa-1,b-1)<<" = ";
			cout<<fun(c,d)
			-fun(aa-1,d)
			-fun(c,b-1)
			+fun(aa-1,b-1)<<endl;
		}
	}
	return 0;
}
